SELECT a.*, u.avatar as author_avatar FROM psi_blog_article a LEFT JOIN sys_blog_user u ON a.author_id = u.id WHERE a.del_flag = '0' AND a.status = '1'
AND a.title LIKE CONCAT('%', #{query.title}, '%')
AND a.author_id = #{query.authorId}
AND a.status = #{query.status}
AND a.category_id = #{query.categoryId}
AND MONTH(a.publish_time) = MONTH(#{query.publishTime}) AND DAY(a.publish_time) = DAY(#{query.publishTime})
AND a.category_name = #{query.categoryName}
AND a.tags LIKE CONCAT('%', #{query.tags}, '%')
ORDER BY a.is_top DESC, a.create_time DESC

mapper.update:
UPDATE psi_blog_article
SET view_count = view_count + 1
WHERE id = #{id}

UPDATE psi_blog_article
SET like_count = like_count + 1
WHERE id = #{id}

UPDATE psi_blog_article
SET like_count = CASE WHEN like_count > 0 THEN like_count - 1 ELSE 0 END
WHERE id = #{id}

UPDATE psi_blog_article
SET collect_count = collect_count + 1
WHERE id = #{id}

UPDATE psi_blog_article
SET collect_count = CASE WHEN collect_count > 0 THEN collect_count - 1 ELSE 0 END
WHERE id = #{id}

UPDATE psi_blog_article
SET comment_count = comment_count + 1
WHERE id = #{id}

UPDATE psi_blog_article
SET comment_count = CASE WHEN comment_count > 0 THEN comment_count - 1 ELSE 0 END
WHERE id = #{id}
